const input = $input.first().json;
const body = input.body || {};

if (!body.token) {
  return [{ json: { error: 'Token is required', statusCode: 401, valid: false } }];
}

try {
  const parts = body.token.split('.');
  if (parts.length !== 3) {
    return [{ json: { error: 'Invalid token format', statusCode: 401, valid: false } }];
  }

  let payload = parts[1].replace(/-/g, '+').replace(/_/g, '/');
  while (payload.length % 4) payload += '=';
  const decoded = JSON.parse(Buffer.from(payload, 'base64').toString('utf8'));

  if (!decoded.user_id) {
    return [{ json: { error: 'Invalid token: missing user_id', statusCode: 401, valid: false } }];
  }

  if (decoded.exp && decoded.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: 'Token expired', statusCode: 401, valid: false } }];
  }

  // Two modes: vendor_id (load from DB) or direct credentials
  const hasVendorId = !!body.vendor_id;
  const hasDirectCreds = body.source && body.source_url;

  if (!hasVendorId && !hasDirectCreds) {
    return [{ json: { error: 'Either vendor_id or (source + source_url) is required', statusCode: 400, valid: false } }];
  }

  return [{ json: {
    valid: true,
    user_id: decoded.user_id,
    vendor_id: body.vendor_id || null,
    source: body.source || null,
    source_url: body.source_url || null,
    source_api_key: body.source_api_key || null,
    source_api_secret: body.source_api_secret || null,
    mode: hasVendorId ? 'vendor_id' : 'direct'
  } }];
} catch (e) {
  return [{ json: { error: 'Token decode failed: ' + e.message, statusCode: 401, valid: false } }];
}

const result = $input.first().json;
const vendors = Array.isArray(result) ? result : [result];

if (!vendors.length || !vendors[0].id) {
  return [{ json: { error: 'Vendor not found or access denied', statusCode: 404, testReady: false } }];
}

const v = vendors[0];
return [{ json: {
  testReady: true,
  vendor_id: v.id,
  vendor_name: v.name,
  source: v.source,
  source_url: v.source_url,
  source_api_key: v.source_api_key,
  source_api_secret: v.source_api_secret
} }];

const data = $input.first().json;
return [{ json: {
  testReady: true,
  vendor_id: null,
  vendor_name: null,
  source: data.source,
  source_url: data.source_url,
  source_api_key: data.source_api_key,
  source_api_secret: data.source_api_secret
} }];

const { source, source_url, source_api_key, source_api_secret, vendor_id, vendor_name } = $input.first().json;

if (!source_url) {
  return [{ json: { success: false, error: 'source_url is required for connection test' } }];
}

const cleanUrl = source_url.replace(/\/+$/, '');
let connectionResult = { connection: 'failed', product_count: null, shop_name: null, error: null };

try {
  let url, headers, parseResponse;

  switch (source) {
    case 'shopify': {
      if (!source_api_key) {
        return [{ json: { success: false, error: 'source_api_key (Shopify Access Token) is required' } }];
      }

      // Get product count
      url = `${cleanUrl}/admin/api/2024-01/products/count.json`;
      headers = { 'X-Shopify-Access-Token': source_api_key };

      const countResp = await fetch(url, { method: 'GET', headers, signal: AbortSignal.timeout(15000) });

      if (!countResp.ok) {
        connectionResult.error = `Shopify API error: HTTP ${countResp.status} ${countResp.statusText}`;
        break;
      }

      const countData = await countResp.json();
      connectionResult.product_count = countData.count || 0;

      // Get shop name
      try {
        const shopResp = await fetch(`${cleanUrl}/admin/api/2024-01/shop.json`, { method: 'GET', headers, signal: AbortSignal.timeout(10000) });
        if (shopResp.ok) {
          const shopData = await shopResp.json();
          connectionResult.shop_name = shopData.shop?.name || null;
        }
      } catch (e) {
        // Non-critical, shop name is optional
      }

      connectionResult.connection = 'ok';
      break;
    }

    case 'woocommerce': {
      if (!source_api_key) {
        return [{ json: { success: false, error: 'source_api_key (WooCommerce Consumer Key) is required' } }];
      }

      const basicAuth = Buffer.from(`${source_api_key}:${source_api_secret || ''}`).toString('base64');
      headers = { 'Authorization': `Basic ${basicAuth}` };

      // Get products with per_page=1 to validate and get total count from headers
      url = `${cleanUrl}/wp-json/wc/v3/products?per_page=1`;
      const wcResp = await fetch(url, { method: 'GET', headers, signal: AbortSignal.timeout(15000) });

      if (!wcResp.ok) {
        connectionResult.error = `WooCommerce API error: HTTP ${wcResp.status} ${wcResp.statusText}`;
        break;
      }

      // WooCommerce returns total count in X-WP-Total header
      const totalHeader = wcResp.headers.get('X-WP-Total');
      connectionResult.product_count = totalHeader ? parseInt(totalHeader) : null;

      // Get shop name from system status
      try {
        const sysResp = await fetch(`${cleanUrl}/wp-json/wc/v3/system_status`, { method: 'GET', headers, signal: AbortSignal.timeout(10000) });
        if (sysResp.ok) {
          const sysData = await sysResp.json();
          connectionResult.shop_name = sysData.environment?.site_url || sysData.settings?.store_name || cleanUrl;
        }
      } catch (e) {
        // Non-critical
      }

      connectionResult.connection = 'ok';
      break;
    }

    case 'prestashop': {
      if (!source_api_key) {
        return [{ json: { success: false, error: 'source_api_key (PrestaShop Webservice Key) is required' } }];
      }

      const psAuth = Buffer.from(`${source_api_key}:`).toString('base64');
      headers = { 'Authorization': `Basic ${psAuth}` };

      // Get products list with limit=1 to validate
      url = `${cleanUrl}/api/products?output_format=JSON&display=[id]&limit=1`;
      const psResp = await fetch(url, { method: 'GET', headers, signal: AbortSignal.timeout(15000) });

      if (!psResp.ok) {
        connectionResult.error = `PrestaShop API error: HTTP ${psResp.status} ${psResp.statusText}`;
        break;
      }

      // Try to get total product count
      try {
        const countUrl = `${cleanUrl}/api/products?output_format=JSON&display=[id]`;
        const countResp = await fetch(countUrl, { method: 'GET', headers, signal: AbortSignal.timeout(15000) });
        if (countResp.ok) {
          const countData = await countResp.json();
          connectionResult.product_count = countData.products ? countData.products.length : null;
        }
      } catch (e) {
        // Non-critical
      }

      // Get shop name
      try {
        const shopUrl = `${cleanUrl}/api/shops?output_format=JSON&display=[name]&limit=1`;
        const shopResp = await fetch(shopUrl, { method: 'GET', headers, signal: AbortSignal.timeout(10000) });
        if (shopResp.ok) {
          const shopData = await shopResp.json();
          connectionResult.shop_name = shopData.shops?.[0]?.name || null;
        }
      } catch (e) {
        // Non-critical
      }

      connectionResult.connection = 'ok';
      break;
    }

    case 'api': {
      headers = {};
      if (source_api_key) {
        headers['Authorization'] = `Bearer ${source_api_key}`;
      }

      url = cleanUrl;
      const apiResp = await fetch(url, { method: 'GET', headers, signal: AbortSignal.timeout(15000) });

      if (!apiResp.ok) {
        connectionResult.error = `API error: HTTP ${apiResp.status} ${apiResp.statusText}`;
        break;
      }

      // Try to parse response for product count hints
      try {
        const apiData = await apiResp.json();
        if (apiData.total !== undefined) connectionResult.product_count = apiData.total;
        else if (apiData.count !== undefined) connectionResult.product_count = apiData.count;
        else if (Array.isArray(apiData)) connectionResult.product_count = apiData.length;
        if (apiData.name) connectionResult.shop_name = apiData.name;
      } catch (e) {
        // Response may not be JSON
      }

      connectionResult.connection = 'ok';
      break;
    }

    case 'excel': {
      // Excel sources don't have a connection to test
      connectionResult.connection = 'ok';
      connectionResult.shop_name = 'Excel/CSV source';
      break;
    }

    default: {
      return [{ json: { success: false, error: `Unsupported source type: ${source}` } }];
    }
  }
} catch (e) {
  connectionResult.error = `Connection failed: ${e.message}`;
  connectionResult.connection = 'failed';
}

// Build response
const response = {
  success: connectionResult.connection === 'ok',
  connection: connectionResult.connection,
  source,
  source_url: cleanUrl
};

if (vendor_id) response.vendor_id = vendor_id;
if (vendor_name) response.vendor_name = vendor_name;
if (connectionResult.product_count !== null) response.product_count = connectionResult.product_count;
if (connectionResult.shop_name) response.shop_name = connectionResult.shop_name;
if (connectionResult.error) response.error = connectionResult.error;

return [{ json: response }];

const result = $input.first().json;

// If we tested with a vendor_id, update the vendor's sync_status and product_count
if (result.vendor_id && result.success) {
  const updatePayload = {
    sync_status: 'active',
    last_sync_at: new Date().toISOString()
  };
  if (result.product_count !== undefined) {
    updatePayload.product_count = result.product_count;
  }

  try {
    const patchUrl = `https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1/vendors?id=eq.${result.vendor_id}`;
    await fetch(patchUrl, {
      method: 'PATCH',
      headers: {
        'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJhbm9uIiwKICAgICJpc3MiOiAic3VwYWJhc2UtZGVtbyIsCiAgICAiaWF0IjogMTY0MTc2OTIwMCwKICAgICJleHAiOiAxNzk5NTM1NjAwCn0.dc_X5iR_VP_qT0zsiyj_I_OZ2T9FtRU2BBNWN8Bu4GE',
        'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(updatePayload),
      signal: AbortSignal.timeout(10000)
    });
  } catch (e) {
    // Non-critical: test result is still valid even if status update fails
    result.status_update_error = e.message;
  }
} else if (result.vendor_id && !result.success) {
  // Mark as pending/error if test failed
  try {
    const patchUrl = `https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1/vendors?id=eq.${result.vendor_id}`;
    await fetch(patchUrl, {
      method: 'PATCH',
      headers: {
        'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJhbm9uIiwKICAgICJpc3MiOiAic3VwYWJhc2UtZGVtbyIsCiAgICAiaWF0IjogMTY0MTc2OTIwMCwKICAgICJleHAiOiAxNzk5NTM1NjAwCn0.dc_X5iR_VP_qT0zsiyj_I_OZ2T9FtRU2BBNWN8Bu4GE',
        'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ sync_status: 'error' }),
      signal: AbortSignal.timeout(10000)
    });
  } catch (e) {
    // Non-critical
  }
}

return [{ json: result }];
